    orientation?: "horizontal" | "vertical"
  }
>({
  size: "default",
  variant: "default",
  spacing: 0,
  orientation: "horizontal",
})

function ToggleGroup({ variant, size, spacing, orientation, children, ...props }) {
  return (
    <ToggleGroupPrimitive.Root
      data-orientation={orientation}
      style={{ "--gap": spacing } as React.CSSProperties}
      className={cn("data-[orientation=vertical]:flex-col", className)}
    >
      <ToggleGroupContext.Provider value={{ variant, size, spacing, orientation }}>
        {children}
      </ToggleGroupContext.Provider>
    </ToggleGroupPrimitive.Root>
  )
}

function ToggleGroupItem({ ...props }) {
  const context = React.useContext(ToggleGroupContext)
  // Uses context for inherited styling
}
```

**Example: Sidebar** (`/apps/v4/styles/radix-nova/ui/sidebar.tsx` - lines 34-53)
```typescript
type SidebarContextProps = {
  state: "expanded" | "collapsed"
  open: boolean
  setOpen: (open: boolean) => void
  // ... more state
}

function SidebarProvider({ defaultOpen, open, onOpenChange, children }) {
  const state = open ? "expanded" : "collapsed"
  // Provides rich context to child components
}
```

### 7. **Tailwind v3 Usage & CSS Variables**

**Version:** Tailwind CSS v3.4.18 (from package.json)

**CSS Variable Setup** (in `/apps/v4/app/globals.css`):
- Uses OKLch color space: `oklch(L C H)` format
- Defines 30+ design tokens via CSS custom properties
- Layout tokens: `--radius`, `--radius-sm`, `--radius-md`, etc.
- Color tokens: `--background`, `--foreground`, `--primary`, `--muted`, etc.

**Key CSS Variables:**
```css
:root {
  --radius: 0.625rem;
  --background: oklch(1 0 0);
  --foreground: oklch(0.145 0 0);
  --primary: oklch(0.205 0 0);
  --border: oklch(0.922 0 0);
  --sidebar-width: 16rem;  /* Set in SidebarProvider */
  --sidebar-width-icon: 3rem;
}
```

**Tailwind theme integration:**
```css
@theme inline {
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --color-background: var(--background);
  --color-primary: var(--primary);
  /* ... maps all CSS vars to Tailwind theme */
}
```

**Custom Tailwind utilities:**
- `no-scrollbar` utility defined in `/packages/shadcn/src/tailwind.css`
- `data-*` custom variants for state styling

### 8. **Breadcrumb Component (Linear Flow Pattern)**

Path: `/apps/v4/styles/radix-nova/ui/breadcrumb.tsx`

Relevant for stepper as it has similar linear progression:
- Compound component with: `Breadcrumb`, `BreadcrumbList`, `BreadcrumbItem`, `BreadcrumbLink`, `BreadcrumbPage`, `BreadcrumbSeparator`, `BreadcrumbEllipsis`
- Uses `data-slot` attributes for styling
- Uses semantic HTML: `<nav>`, `<ol>`, `<li>`
- Separators between items (similar to stepper steps)
- **Does NOT use orientation** - always horizontal

### 9. **Component Registration Pattern**

Registry location: `/apps/v4/registry/new-york-v4/ui/_registry.ts`

**Standard registry entry format:**
```typescript
{
  name: "breadcrumb",
  type: "registry:ui",
  dependencies: ["radix-ui"],
  files: [
    {
      path: "ui/breadcrumb.tsx",
      type: "registry:ui",
    },
  ],
}
```

For a stepper component, you would add:
```typescript
{
  name: "stepper",
  type: "registry:ui",
  dependencies: ["radix-ui"],
  registryDependencies: ["button"],  // if using buttons
  files: [
    {
      path: "ui/stepper.tsx",
      type: "registry:ui",
    },
  ],
}
```

### 10. **Design Patterns Summary**

**Recommended approach for a Stepper component:**

1. **Use compound components pattern** (like Breadcrumb, ToggleGroup)
   ```
   <Stepper currentStep={1} orientation="horizontal">
     <StepperItem step={1}>
       <StepperTrigger>Step 1</StepperTrigger>
       <StepperContent>Content 1</StepperContent>
     </StepperItem>
   </Stepper>
   ```

2. **Implement orientation support** with CVA:
   ```typescript
   const stepperVariants = cva("flex gap-4", {
     variants: {
       orientation: {
         horizontal: "flex-row",
         vertical: "flex-col",
       }
     }
   })
   ```

3. **Use data attributes** for state styling:
   - `data-step="1"` - step number
   - `data-state="completed"/"active"/"upcoming"` - step state
   - `data-orientation="horizontal"/"vertical"`
   - `data-active={isActive}` - for active step indicator

4. **Use React Context** for passing down orientation and state
   - Similar to `ToggleGroupContext` or `SidebarContext`

5. **Leverage existing utilities**:
   - Import `cn` from `@/lib/utils` for class merging
   - Use `Slot` from `radix-ui` for composition
   - Use existing components (Button, Separator) as children

### 11. **Key Files Reference**

| Purpose | File Path |
|---------|-----------|
| Orientation pattern example | `/apps/v4/styles/radix-nova/ui/toggle-group.tsx` |
| CVA variant examples | `/apps/v4/styles/radix-nova/ui/button.tsx` |
| Compound component with context | `/apps/v4/styles/radix-nova/ui/sidebar.tsx` |
| Linear flow pattern (breadcrumb) | `/apps/v4/styles/radix-nova/ui/breadcrumb.tsx` |
| Data state attributes | `/apps/v4/styles/radix-nova/ui/accordion.tsx` |
| Orientation in Tailwind | `/packages/shadcn/src/tailwind.css` |
| Design tokens | `/apps/v4/app/globals.css` |
| Registry format | `/apps/v4/registry/new-york-v4/ui/_registry.ts` |

### 12. **Related Components to Study**

For building a stepper, these provide the best patterns:
1. **Tabs** (`tabs.tsx`) - state management, orientation support
2. **ToggleGroup** (`toggle-group.tsx`) - context-based child component coordination
3. **Sidebar** (`sidebar.tsx`) - complex state management with context
4. **Breadcrumb** (`breadcrumb.tsx`) - linear progression pattern
5. **Pagination** (`pagination.tsx`) - step/page state with `data-active`

