**Types and Context:**

```typescript
type StepperContextProps = {
  activeStep: number
  setActiveStep: (step: number) => void
  orientation: "horizontal" | "vertical"
  linear: boolean
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

type StepperItemContextProps = {
  step: number
  state: "completed" | "active" | "upcoming"
}

const StepperItemContext = React.createContext<StepperItemContextProps | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}
```

**`Stepper` -- Root container:**

```typescript
function Stepper({
  activeStep: activeStepProp,
  onActiveStepChange: setActiveStepProp,
  defaultActiveStep = 1,
  orientation = "horizontal",
  linear = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep?: number
  onActiveStepChange?: (step: number) => void
  defaultActiveStep?: number
  orientation?: "horizontal" | "vertical"
  linear?: boolean
}) {
  const [_activeStep, _setActiveStep] = React.useState(defaultActiveStep)
  const activeStep = activeStepProp ?? _activeStep
  const setActiveStep = React.useCallback(
    (step: number) => {
      if (setActiveStepProp) {
        setActiveStepProp(step)
      } else {
        _setActiveStep(step)
      }
    },
    [setActiveStepProp]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, setActiveStep, orientation, linear }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "group/stepper flex gap-4 data-[orientation=horizontal]:flex-row data-[orientation=horizontal]:items-center data-[orientation=vertical]:flex-col",
          className
        )}
        role="group"
        aria-label="stepper"
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}
```

Key design notes:
- Controlled/uncontrolled pattern matches `SidebarProvider` exactly (lines 56-89 of sidebar.tsx)
- `data-orientation` attribute matches the Tabs pattern
- `group/stepper` naming matches `group/tabs`, `group/sidebar-wrapper` pattern
- `role="group"` with `aria-label` for accessibility (matches Carousel's `role="region"`)
- Uses plain `function` declaration, not arrow function or forwardRef

**`StepperItem` -- Individual step wrapper:**

```typescript
function StepperItem({
  step,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
}) {
  const { activeStep } = useStepper()
  const state = step < activeStep
    ? "completed"
    : step === activeStep
      ? "active"
      : "upcoming"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        className={cn(
          "group/stepper-item flex items-center gap-3 group-data-[orientation=vertical]/stepper:flex-row",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}
```

Key design notes:
- Computes `state` from context (`completed`/`active`/`upcoming`) -- these become `data-state` attributes for CSS styling
- `data-step` and `data-state` enable CSS-driven styling: `data-[state=completed]:...`, `data-[state=active]:...`
- `group/stepper-item` enables children to style based on parent state: `group-data-[state=completed]/stepper-item:...`

**`StepperTrigger` -- Clickable button:**

```typescript
function StepperTrigger({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep, linear, activeStep } = useStepper()
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex items-center gap-3 rounded-md text-sm font-medium outline-none transition-colors focus-visible:border-ring focus-visible:ring-[3px] focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => setActiveStep(step)}
      disabled={linear && step > activeStep}
      {...props}
    />
  )
}
```

Key design notes:
- A native `button` element for accessibility
- Disables navigation to future steps when `linear` is true
- Focus-visible styles match the codebase pattern (e.g., accordion trigger, tabs trigger)
- The user composes `StepperIndicator`, `StepperTitle`, etc. as children

